(()=>{'use strict';
const APP_VERSION='Solomon DOIT Pro V2.9.0';
const T=v=>String(v??'').trim();
const N=v=>Number(String(v??'').replace(/,/g,''))||0;
const B=n=>N(n).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2});
const $=s=>document.querySelector(s);
let rawPayload=null,rawRows=[],meta={},patched=false;
function rowsOf(p){return p?.rows||p||[]}
function cleanPs(v){const parts=T(v).split(/\s+/).filter(Boolean);if(!parts.length)return'';if(parts.length===2&&parts[0]===parts[1])return parts[0];const out=[];parts.forEach(x=>{if(!out.includes(x))out.push(x)});return out.join(' ')}
function appKey(){return T(meta.id||meta.version_id||rawPayload?.version_id||meta.file_name||'active')}
function keys(prefix){const out=[];for(let i=0;i<localStorage.length;i++){const k=localStorage.key(i)||'';if(k.startsWith(prefix))out.push(k)}return out}
function manualKey(){const k=appKey();const existing=keys('doit-manual-v1:');if(k&&k!=='active')return 'doit-manual-v1:'+k;if(existing.length)return existing[0];const sk=keys('doit-json:')[0];return sk?'doit-manual-v1:'+sk.replace(/^doit-json:/,''):'doit-manual-v1:'+k}
function read(k,d){try{return JSON.parse(localStorage.getItem(k)||'')||d}catch{return d}}
function write(k,v){localStorage.setItem(k,JSON.stringify(v))}
function dates(){return[...new Set(rawRows.map(r=>T(r.date)).filter(Boolean))].sort()}
function selectedDates(){return[...new Set((window.DOIT_SELECTED_DATES||[]).map(T).filter(Boolean))].sort()}
function selectedPs(){return[...new Set((window.DOIT_SELECTED_PS_LIST||[]).map(cleanPs).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'th'))}
function getScope(){return{dates:selectedDates(),dateKey:T(window.DOIT_SELECTED_DATE_KEY),ps:selectedPs(),psKey:T(window.DOIT_SELECTED_PS_KEY),receiver:T($('#storeSelect')?.value),brand:T($('#brandSelect')?.value),type:T($('#typeSelect')?.value),q:T($('#q')?.value).toLowerCase()}}
function setMsg(s){const m=$('#msg');if(m)m.textContent=s}
function renameInsertButton(){const b=$('#manualAddBtn');if(b)b.textContent='+ แทรกออเดอร์'}
function lockTitle(){try{document.title=APP_VERSION}catch{}const t=document.querySelector('.title');if(t)t.textContent=APP_VERSION;const f=document.querySelector('footer');if(f&&/Solomon DOIT Pro/i.test(f.textContent||''))f.textContent=APP_VERSION}
function patchLoad(){const app=window.DOIT_JSON_APP;if(!app||app.__appCoordinator290)return false;const old=app.load.bind(app);app.load=(payload,m={})=>{rawPayload=payload;meta=m||{};const arr=rowsOf(payload);if(Array.isArray(arr)&&arr.length){rawRows=arr;window.__doitRawRows290=arr;window.DOIT_ALL_DATES=dates();window.DOIT_AVAILABLE_DATES=window.DOIT_ALL_DATES}const res=old(payload,m);setTimeout(syncUi,0);setTimeout(syncUi,250);setTimeout(renderManualRows,350);return res};app.__appCoordinator290=true;patched=true;return true}
function syncUi(){lockTitle();renameInsertButton();const ds=selectedDates();const p=$('#datePreview');if(p){if(!ds.length)p.textContent='ทุกวัน';else if(ds.length===1)p.textContent=thai(ds[0]);else p.textContent=`เลือก ${ds.length} วัน: ${thai(ds[0])} - ${thai(ds[ds.length-1])}`}const pb=$('#psTickBtn289');if(pb){const ps=selectedPs();pb.textContent=ps.length?`PS: ${ps.length===1?ps[0]:ps.length+' คน'} ▼`:'PS: ทั้งหมด ▼'}window.DOIT_APP_SCOPE=getScope();setTimeout(renderManualRows,0)}
function thai(s){const p=T(s).split('-');return p.length===3?`${p[2]}/${p[1]}/${p[0]}`:s}
function esc(s){return T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function ensureModalCss(){if($('#manualModal290Css'))return;const st=document.createElement('style');st.id='manualModal290Css';st.textContent='.manualOverlay290{position:fixed;inset:0;background:rgba(15,23,42,.55);z-index:180;display:none;align-items:center;justify-content:center;padding:14px}.manualOverlay290.on{display:flex}.manualSheet290{width:min(94vw,560px);background:#fff;border-radius:18px;box-shadow:0 24px 80px rgba(0,0,0,.38);overflow:hidden}.manualHead290{background:#087b34;color:#fff;padding:14px 16px;font-weight:950;display:flex;justify-content:space-between;align-items:center}.manualBody290{padding:14px;display:grid;gap:10px}.manualBody290 label{font-size:12px;font-weight:950;color:#374151}.manualBody290 input{width:100%;height:42px;border:1px solid #cbd5e1;border-radius:10px;padding:0 10px;font-weight:900}.manualFoot290{display:grid;grid-template-columns:1fr 1fr;gap:10px;padding:12px;border-top:1px solid #e5e7eb}.manualFoot290 button{height:44px;border-radius:10px;font-weight:950}.manualCancel290{background:#fff;border:1px solid #d1d5db;color:#4b5563}.manualSave290{background:#087b34;border:0;color:#fff}.manualOrderRow290 td{background:#fffdf3!important}.manualBadge290{display:inline-block;background:#fef3c7;color:#92400e;border:1px solid #f59e0b;border-radius:999px;padding:2px 7px;font-size:11px;font-weight:950}.manualQtyTable290{width:80px;height:34px;border:1px solid #f59e0b;border-radius:8px;text-align:center;font-weight:900;background:#fffbeb}.manualDel290{height:30px;border:1px solid #ef4444;background:#fef2f2;color:#b91c1c;border-radius:8px;font-weight:950;padding:0 8px}.manualHint290{font-size:11px;color:#92400e;display:block;margin-top:2px}';document.head.appendChild(st)}
function openManual(){ensureModalCss();let ov=$('#manualOverlay290');if(!ov){ov=document.createElement('div');ov.id='manualOverlay290';ov.className='manualOverlay290';ov.innerHTML=`<div class="manualSheet290"><div class="manualHead290"><span>แทรกออเดอร์ลอย</span><button class="manualCancel290" type="button">ปิด</button></div><div class="manualBody290"><div><label>พิมพ์ชื่อออเดอร์/รายการ *</label><input id="manualName290" placeholder="พิมพ์ชื่อรายการ"></div><div><label>ราคา/หน่วย</label><input id="manualUnit290" type="number" step="0.01" min="0" value="0"></div><div><label>รหัส SKU ถ้ามี</label><input id="manualCode290" placeholder="ไม่บังคับ"></div><div><label>กลุ่ม/แบรนด์</label><input id="manualBrand290" value="แทรกเอง"></div><div class="manualHint290">รายการนี้เป็นออเดอร์ลอยในหน้าถอดของ ยังไม่ผูกกับร้านใด จนกว่าจะเลือกส่งร้านและกรอกจำนวนในตาราง</div></div><div class="manualFoot290"><button class="manualCancel290" type="button">ยกเลิก</button><button class="manualSave290" type="button">บันทึก</button></div></div>`;document.body.appendChild(ov);ov.addEventListener('click',e=>{if(e.target===ov||e.target.classList.contains('manualCancel290'))ov.classList.remove('on')});ov.querySelector('.manualSave290').onclick=saveManualModal}
$('#manualName290').value='';$('#manualUnit290').value='0';$('#manualCode290').value='';$('#manualBrand290').value='แทรกเอง';ov.classList.add('on');setTimeout(()=>$('#manualName290')?.focus(),50)}
function saveManualModal(){const sc=getScope();const name=T($('#manualName290')?.value);const unit=N($('#manualUnit290')?.value);const code=T($('#manualCode290')?.value);const brand=T($('#manualBrand290')?.value)||'แทรกเอง';if(!name)return alert('กรุณาพิมพ์ชื่อออเดอร์/รายการ');const arr=read(manualKey(),[]);arr.push({id:Date.now(),floating:true,store:'',start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:sc.psKey||T($('#psSelect')?.value),dateKey:sc.dateKey,psKey:sc.psKey,name,qty:0,qtyByStore:{},unit,code,brand,size:'',type:'MANUAL'});write(manualKey(),arr);$('#manualOverlay290')?.classList.remove('on');setMsg('แทรกออเดอร์ลอยแล้ว เลือกร้านและกรอกจำนวนในตารางเมื่อต้องการส่ง');renderManualRows();document.dispatchEvent(new CustomEvent('doit:stateChanged',{detail:{manual:true,inserted:true,floating:true}}))}
function isFloating(x){return !!x.floating||!T(x.store)}
function manualMatchesScope(x,sc){const start=T($('#startDate')?.value),end=T($('#endDate')?.value),ps=T($('#psSelect')?.value);if(x.dateKey&&sc.dateKey&&x.dateKey!==sc.dateKey)return false;if(!x.dateKey){if(start&&T(x.start)!==start)return false;if(end&&T(x.end)!==end)return false}if(x.psKey&&sc.psKey&&x.psKey!==sc.psKey)return false;if(!x.psKey&&ps&&T(x.ps)!==ps)return false;if(!isFloating(x)&&sc.receiver&&T(x.store)!==sc.receiver)return false;if(sc.brand&&T(x.brand)!==sc.brand)return false;if(sc.type&&T(x.type||'MANUAL')!==sc.type)return false;if(sc.q&&!([x.name,x.code,x.brand,x.store,'แทรกออเดอร์','แทรกเอง'].join(' ').toLowerCase().includes(sc.q)))return false;return true}
function isPickTable(){const h=[...document.querySelectorAll('#table th')].map(x=>T(x.textContent)).join('|');return /จำนวนส่งร้านนี้/.test(h)&&/จำนวนออเดอร์รวม/.test(h)}
function manualRows(){const sc=getScope();return read(manualKey(),[]).filter(x=>manualMatchesScope(x,sc))}
function qtyForCurrentReceiver(x,sc){if(isFloating(x)){if(!sc.receiver)return 0;return N((x.qtyByStore||{})[sc.receiver])}return N(x.qty)}
function renderManualRows(){ensureModalCss();document.querySelectorAll('.manualOrderRow290').forEach(x=>x.remove());const tb=$('#table tbody');if(!tb||!isPickTable())return;const sc=getScope();const items=manualRows();if(!items.length)return;const frag=document.createDocumentFragment();items.forEach((x,i)=>{const qty=qtyForCurrentReceiver(x,sc),unit=N(x.unit),amt=qty*unit;const tr=document.createElement('tr');tr.className='manualOrderRow290';tr.dataset.id=String(x.id);tr.innerHTML=`<td>M${i+1}</td><td>${esc(x.brand||'แทรกเอง')}<br><span class="manualBadge290">ออเดอร์ลอย</span></td><td>${esc(x.code||'-')}</td><td class="p"><b>${esc(x.name)}</b><small>${sc.receiver?'กรอกจำนวนเพื่อส่งร้านนี้':'เลือกส่งร้านแล้วกรอกจำนวน'}</small></td><td>แทรกเอง<span class="manualHint290">ไม่ผูกกับร้านจนกว่าจะกรอกจำนวน</span></td><td><input class="manualQtyTable290" data-id="${esc(x.id)}" type="number" inputmode="numeric" min="0" step="1" value="${qty||''}" ${sc.receiver?'':'disabled'}></td><td>-</td><td><button class="manualDel290" data-id="${esc(x.id)}" type="button">ลบ</button></td><td class="good manualRemain290">${qty}</td><td class="manualAmt290">${B(amt)}</td>`;frag.appendChild(tr)});tb.appendChild(frag)}
function updateManualQty(id,qty){const sc=getScope();if(!sc.receiver)return alert('กรุณาเลือกร้านจริงก่อนกรอกจำนวนส่ง');const arr=read(manualKey(),[]),x=arr.find(v=>String(v.id)===String(id));if(!x)return;if(isFloating(x)){x.qtyByStore=x.qtyByStore||{};x.qtyByStore[sc.receiver]=N(qty);x.qty=Object.keys(x.qtyByStore).reduce((s,k)=>s+N(x.qtyByStore[k]),0)}else x.qty=N(qty);write(manualKey(),arr);const tr=document.querySelector(`.manualOrderRow290[data-id="${CSS.escape(String(id))}"]`);if(tr){tr.querySelector('.manualRemain290').textContent=String(N(qty));tr.querySelector('.manualAmt290').textContent=B(N(qty)*N(x.unit))}document.dispatchEvent(new CustomEvent('doit:stateChanged',{detail:{manual:true,id,qty:N(qty),receiver:sc.receiver}}))}
function deleteManual(id){const arr=read(manualKey(),[]),x=arr.find(v=>String(v.id)===String(id));if(!x)return;if(!confirm('ลบออเดอร์แทรก: '+T(x.name)+' ?'))return;write(manualKey(),arr.filter(v=>String(v.id)!==String(id)));renderManualRows();document.dispatchEvent(new CustomEvent('doit:stateChanged',{detail:{manual:true,id,deleted:true}}))}
function bindManual(){if(document.__manualModal290)return;document.__manualModal290=true;document.addEventListener('click',e=>{const btn=e.target?.closest?.('#manualAddBtn');const del=e.target?.closest?.('.manualDel290');if(btn){e.preventDefault();e.stopImmediatePropagation();openManual();return}if(del){e.preventDefault();e.stopImmediatePropagation();deleteManual(del.dataset.id);return}},true);document.addEventListener('input',e=>{const inp=e.target?.closest?.('.manualQtyTable290');if(inp)updateManualQty(inp.dataset.id,inp.value)},true);document.addEventListener('change',e=>{const inp=e.target?.closest?.('.manualQtyTable290');if(inp)updateManualQty(inp.dataset.id,inp.value)},true);['doit:scopeRendered','doit:selectedDatesChanged','doit:psChanged'].forEach(ev=>document.addEventListener(ev,()=>setTimeout(renderManualRows,80)));document.addEventListener('change',e=>{if(e.target?.id==='storeSelect')setTimeout(renderManualRows,80)},true)}
function health(){return{version:APP_VERSION,patched,appKey:appKey(),rows:rawRows.length,scope:getScope(),manualKey:manualKey(),manualRows:manualRows().length,scripts:[...document.scripts].map(s=>s.getAttribute('src')).filter(Boolean).filter(s=>/doit|coordinator|fix|owner|drawer/i.test(s))}}
function expose(){window.DOIT_APP_COORDINATOR={version:APP_VERSION,getScope,health,openManual,manualKey,renderManualRows,rerender:()=>window.DOIT_JSON_APP?.rerender?.()}}
function boot(){patchLoad();bindManual();expose();syncUi();let n=0;const tick=()=>{patchLoad();bindManual();expose();syncUi();renderManualRows();if(++n<10)setTimeout(tick,600)};setTimeout(tick,300)}
document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();
})();